/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper to convert an array [x, y, z] to a unique string key
    const pointToKey = (p) => p.join(',');

    // Step 1: Check if target is in the initial set (k=0)
    const initialPointsSet = new Set();
    for (const p of points) {
        const key = pointToKey(p);
        initialPointsSet.add(key);
    }

    const targetKey = pointToKey(target);
    if (initialPointsSet.has(targetKey)) {
        return 0;
    }

    // Set to store all unique points generated so far (from generations 0 to k-1)
    // We use a Set to manage uniqueness efficiently.
    let currentPointsKeys = new Set(points.map(pointToKey));
    let currentPointsArray = points.map(p => [...p]); // Array form for easy iteration

    let k = 0;
    const MAX_ITERATIONS = 10000; // Safety break, although given constraints, it should converge or fail relatively fast

    while (k < MAX_ITERATIONS) {
        k++;
        const nextGenerationPoints = [];
        const newlyGeneratedKeys = new Set();

        // The points available for generation k are all points from generation 0 up to k-1.
        // currentPointsArray holds all unique points found up to generation k-1.
        const availablePoints = currentPointsArray;

        const N = availablePoints.length;

        if (N < 2) {
            // Cannot form pairs if there are less than 2 distinct points available
            return -1;
        }

        // Generate new points by pairing every distinct pair (a, b) from availablePoints
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = availablePoints[i];
                const p2 = availablePoints[j];

                // Check the distinctness condition based on coordinates, as required by the problem
                // "选择的两个点必须具有不同的(x, y, z) 坐标。"
                // Since we are iterating over unique points in availablePoints, if i != j, 
                // the points p1 and p2 must have different coordinates if the initial set had no duplicates.
                // However, the problem phrasing is slightly ambiguous regarding whether points generated 
                // in previous generations might have identical coordinates. Since we ensure currentPointsArray
                // only contains unique coordinates (by using Set keys), i != j guarantees different coordinates.

                const newX = Math.floor((p1[0] + p2[0]) / 2);
                const newY = Math.floor((p1[1] + p2[1]) / 2);
                const newZ = Math.floor((p1[2] + p2[2]) / 2);

                const newPoint = [newX, newY, newZ];
                const newKey = pointToKey(newPoint);

                // Only add if it hasn't been generated before (either in previous generations or in this generation)
                if (!currentPointsKeys.has(newKey)) {
                    nextGenerationPoints.push(newPoint);
                    newlyGeneratedKeys.add(newKey);

                    // Check if the target is found
                    if (newKey === targetKey) {
                        return k;
                    }
                }
            }
        }

        // Update the set and array for the next iteration
        if (nextGenerationPoints.length === 0) {
            // No new points were generated, and target wasn't found in this generation.
            return -1;
        }

        // Add all newly generated points to the master list of available points
        for (const newPoint of nextGenerationPoints) {
            currentPointsKeys.add(pointToKey(newPoint));
        }
        currentPointsArray.push(...nextGenerationPoints);
    }

    // If the loop terminates due to max iterations (shouldn't happen under normal constraints if a solution exists)
    return -1;
}

