import scala.collection.mutable

object Solver {
  /**
    * Computes the minimum generation k such that the target point appears in the set of points
    * generated from generation 0 up to generation k.
    *
    * @param points The initial set of 3D points.
    * @param target The target 3D point.
    * @return The minimum generation k, or -1 if unreachable.
    */
  def solve(points: Array[Array[Long]], target: Array[Long]): Long = {
    // Helper to convert a point [x, y, z] to a unique string key
    def pointToKey(p: Array[Long]): String = p.mkString(",")

    // --- Generation 0 Check ---
    val initialPointsSet = mutable.Set[String]()
    val initialPointsMap = mutable.Map[String][Array[Long]]()

    for (p <- points) {
      val key = pointToKey(p)
      initialPointsSet.add(key)
      initialPointsMap.put(key, p)
    }

    val targetKey = pointToKey(target)
    if (initialPointsSet.contains(targetKey)) {
      return 0L
    }

    // State tracking
    // currentPointsKeys: All unique keys generated so far (Gen 0 to k-1)
    var currentPointsKeys: mutable.Set[String] = initialPointsSet
    // currentPointsList: Array form of all unique points generated so far (Gen 0 to k-1)
    var currentPointsList: Array[Array[Long]] = points.to(Array.apply[Array[Long]](_ => Array(0L, 0L, 0L)))

    var k: Int = 0
    val MAX_ITERATIONS = 10000 // Safety break

    while (k < MAX_ITERATIONS) {
      k += 1

      // Points available for generation k are all unique points found up to generation k-1
      val availablePoints = currentPointsList
      val N = availablePoints.length

      if (N < 2) {
        // Cannot form pairs if there are less than 2 distinct points available
        return -1L
      }

      // Use a mutable set to collect newly generated points to maintain uniqueness
      val newlyGeneratedKeys: mutable.Set[String] = mutable.Set()
      val nextGenerationPoints: mutable.List[Array[Long]] = mutable.List()

      // Generate new points by pairing every distinct pair (a, b) from availablePoints
      for (i <- 0 until N) {
        for (j <- i + 1 until N) {
          val p1 = availablePoints(i)
          val p2 = availablePoints(j)

          // Since availablePoints only contains unique coordinates, i != j guarantees different points.

          // Calculate c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
          // Scala's division `/` for Longs performs floor division automatically for positive numbers.
          val newX = (p1(0) + p2(0)) / 2L
          val newY = (p1(1) + p2(1)) / 2L
          val newZ = (p1(2) + p2(2)) / 2L

          val newPoint = Array(newX, newY, newZ)
          val newKey = pointToKey(newPoint)

          // Only add if it hasn't been generated before (i.e., not in currentPointsKeys)
          if (!currentPointsKeys.contains(newKey)) {
            newlyGeneratedKeys.add(newKey)
            nextGenerationPoints.append(newPoint)

            // Check if the target is found
            if (newKey == targetKey) {
              return k.toLong
            }
          }
        }
      }

      // If no new points were generated, and the target wasn't found in this generation, we are stuck.
      if (nextGenerationPoints.isEmpty) {
        return -1L
      }

      // Update state for the next iteration (k+1)

      // 1. Update currentPointsKeys
      for (newKey <- newlyGeneratedKeys) {
        currentPointsKeys.add(newKey)
      }

      // 2. Update currentPointsList by appending new points
      val updatedList = currentPointsList.toArray ++ nextGenerationPoints.toArray
      currentPointsList = updatedList
    }

    // If the loop terminates due to max iterations
    -1L
  }
}
